import { Injectable, signal, computed } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Router } from '@angular/router';
import { tap } from 'rxjs/operators';
import { Observable } from 'rxjs';
import { environment } from '../../../environments/environment';
import { User, Role } from '../models/siteview.models';

const TOKEN_KEY = 'auth_token';
const USER_KEY = 'user';

function readStoredUser(): User | null {
  try {
    const raw = localStorage.getItem(USER_KEY);
    return raw ? (JSON.parse(raw) as User) : null;
  } catch {
    return null;
  }
}

@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly apiUrl = environment.apiUrl;
  private _token = signal<string | null>(localStorage.getItem(TOKEN_KEY));
  private _user = signal<User | null>(readStoredUser());

  readonly isLoggedIn = computed(() => !!this._token());
  readonly token = this._token.asReadonly();
  readonly user = this._user.asReadonly();
  readonly role = computed<Role | null>(() => this._user()?.role ?? null);
  /** planner = Role.admin (writes); viewer = Role.user (reads). */
  readonly isPlanner = computed(() => this._user()?.role === 'admin');

  constructor(
    private http: HttpClient,
    private router: Router,
  ) {}

  login(email: string, password: string): Observable<{ user: User; token: string }> {
    return this.http
      .post<{ user: User; token: string }>(`${this.apiUrl}/auth/login`, { email, password })
      .pipe(tap((response) => this.persistSession(response.token, response.user)));
  }

  register(
    name: string,
    email: string,
    password: string,
    passwordconf: string,
  ): Observable<{ user: User; token: string }> {
    return this.http
      .post<{ user: User; token: string }>(`${this.apiUrl}/auth/register`, {
        name,
        email,
        password,
        passwordconf,
      })
      .pipe(tap((response) => this.persistSession(response.token, response.user)));
  }

  /** Demo Mode — lets reviewers inspect the authenticated planner UI without a live backend. */
  demoLogin(): void {
    const demoUser: User = {
      id: 'demo-admin',
      name: 'Demo Planner',
      email: 'admin@example.com',
      role: 'admin',
    };
    const demoToken = 'demo-token';
    localStorage.setItem('access_token', demoToken);
    localStorage.setItem('isAuthenticated', 'true');
    this.persistSession(demoToken, demoUser);
    this.router.navigate(['/projects']);
  }

  private persistSession(token: string, user: User): void {
    localStorage.setItem(TOKEN_KEY, token);
    localStorage.setItem(USER_KEY, JSON.stringify(user));
    this._token.set(token);
    this._user.set(user);
  }

  logout(): void {
    localStorage.removeItem(TOKEN_KEY);
    localStorage.removeItem(USER_KEY);
    localStorage.removeItem('access_token');
    localStorage.removeItem('isAuthenticated');
    this._token.set(null);
    this._user.set(null);
    this.router.navigate(['/login']);
  }
}
